/// <summary>
/// Extension of the <c>PurchAgreementCreate</c> form for the ETGSPAIN model.
/// </summary>
[ExtensionOf(formStr(PurchAgreementCreate))]
final class PurchAgreementCreateETGSPAIN_Extension
{

}

Method.Source:
/// <summary>
/// Extension of the <c>canClose</c> method.
/// </summary>
/// <returns>
/// Returns a boolean value indicating whether the form can close.
/// </returns>
boolean canClose()
{
    boolean ret = next canClose();

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        if (this.closedOk())
        {
            this.ETGSPAINcreateAgreementLineFromETGSPAINOperation();
        }
    }

    return ret;
}

/// <summary>
/// Method to create agreement lines from operations.
/// </summary>
public void ETGSPAINcreateAgreementLineFromETGSPAINOperation()
{
    ETGSPAINPurchOperationTable  ETGSPAINPurchOperationTable;

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        if (PurchAgreementHeader.ETGSPAINAgreementOperationId)
        {
            ETGSPAINPurchOperationTable = ETGSPAINPurchOperationTable::find(PurchAgreementHeader.ETGSPAINAgreementOperationId);

            if (ETGSPAINPurchOperationTable)
            {
                AgreementLineQuantityCommitment::createAgreementLineFromETGSPAINOperation(ETGSPAINPurchOperationTable, PurchAgreementHeader);
            }
        }
    }
}

/// <summary>
/// Extension of the <c>init</c> method for the ETGSPAIN model.
/// </summary>
/// <remarks>
/// This code is used to show or hide features in Spanish companies.
/// </remarks>
public void init()
{
    next init();

    NoYesId currentCompanyIsSpanishCompany  = CurrentCompanyIsSpanishCompany();

    this.design().controlName(formControlStr(PurchAgreementCreate, PurchAgreementHeader_ETGSPAINPurchCountryRegionIdOrigin)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreementCreate, PurchAgreementHeader_ETGSPAINAgreementOperationId)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreementCreate, ETGSPAINAgreementHeaderDefault_DeliveryTerm)).visible(currentCompanyIsSpanishCompany);

    AgreementHeaderDefault_DS.object(fieldNum(AgreementHeaderDefault, DeliveryTerm)).mandatory(currentCompanyIsSpanishCompany);
}
